import React, { useState } from 'react';
import { Link } from 'react-router-dom';

const NavigationBar = () => {
  const [chainState, setChainState] = useState('ethereum');

  const toggleChain = () => {
    setChainState(prevState => prevState === 'ethereum' ? 'pulsechain' : 'ethereum');
  };

  return (
    <nav className="w-full h-16 bg-black flex items-center justify-between px-6 text-white font-['Chakra Petch']">
      <div className="flex items-center space-x-8">
        <Link to="/" className="text-xl font-semibold">
          LookIntoMaxi
        </Link>
        <div className="flex space-x-6 text-sm">
          <Link to="/delta-discounts">Δ Discounts</Link>
          <Link to="/percent-discounts">% Discounts</Link>
          <Link to="/arbs">Arbs</Link>
          <Link to="/apy">Apy</Link>
          <Link to="/leagues">Leagues</Link>
          <Link to="/gas">Gas</Link>
        </div>
      </div>
      <div className="flex items-center space-x-4">
        <button
          onClick={toggleChain}
          className="w-10 h-10 bg-white rounded-lg flex items-center justify-center"
        >
          {chainState === 'ethereum' ? (
            <svg viewBox="0 0 24 24" width="24" height="24" stroke="currentColor" strokeWidth="2" fill="none" strokeLinecap="round" strokeLinejoin="round" className="text-black">
              <path d="M19 14l-7 7-7-7M19 10l-7 7-7-7M19 6l-7 7-7-7" />
            </svg>
          ) : (
            <svg viewBox="0 0 24 24" width="24" height="24" stroke="currentColor" strokeWidth="2" fill="none" strokeLinecap="round" strokeLinejoin="round" className="text-black">
              <path d="M22 12h-4l-3 9L9 3l-3 9H2" />
            </svg>
          )}
        </button>
        <Link
          to="/buy"
          className="px-6 py-2 border border-white rounded-md text-sm hover:bg-white hover:text-black transition-colors duration-300"
        >
          Buy
        </Link>
      </div>
    </nav>
  );
};

export default NavigationBar;
